// Higher-order component — adds a wrapper layer to DevTools
function withWindowSize(Component) {
  return function WrappedComponent(props) {
    const [size, setSize] = useState({ w: window.innerWidth, h: window.innerHeight });
    useEffect(() => {
      const handler = () => setSize({ w: window.innerWidth, h: window.innerHeight });
      window.addEventListener('resize', handler);
      return () => window.removeEventListener('resize', handler);
    }, []);
    return <Component {...props} windowSize={size} />;
  };
}

// Render prop — even more nesting
function WindowSize({ children }) {
  const [size, setSize] = useState({ w: window.innerWidth, h: window.innerHeight });
  // ... same effect ...
  return children(size);
}

// Usage: each abstraction adds a layer to the tree
<WithAuth>
  <WithWindowSize>
    <WithData url="/api/items">
      {({ user, windowSize, data }) => <Dashboard ... />}
    </WithData>
  </WithWindowSize>
</WithAuth>

// Custom hook — plain function, no wrapper component
function useWindowSize() {
  const [size, setSize] = useState({ w: window.innerWidth, h: window.innerHeight });
  useEffect(() => {
    const handler = () => setSize({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener('resize', handler);
    return () => window.removeEventListener('resize', handler);
  }, []);
  return size;
}

// Usage — flat component tree
function Dashboard() {
  const { user } = useAuth();
  const size = useWindowSize();
  const { data } = useData('/api/items');
  return <main style={{ width: size.w }}>{/* ... */}</main>;
}

class ChatRoom extends React.Component {
  // Mount: fetch history AND subscribe to new messages
  componentDidMount() {
    fetch(`/api/rooms/${this.props.roomId}/history`)
      .then(r => r.json())
      .then(history => this.setState({ history }));

    this.socket = new WebSocket(`wss://chat/${this.props.roomId}`);
    this.socket.onmessage = msg => this.setState(s => ({
      messages: [...s.messages, msg]
    }));
  }

  // Update: must manually compare props to detect room change
  componentDidUpdate(prevProps) {
    if (prevProps.roomId !== this.props.roomId) {
      this.socket.close();
      this.socket = new WebSocket(`wss://chat/${this.props.roomId}`);
      this.socket.onmessage = msg => this.setState(s => ({
        messages: [...s.messages, msg]
      }));
    }
  }

  // Unmount: cleanup for BOTH concerns mixed together
  componentWillUnmount() {
    this.socket.close();
  }
}

function ChatRoom({ roomId }) {
  const [history, setHistory] = useState([]);
  const [messages, setMessages] = useState([]);

  // Concern 1: fetch history — isolated in its own effect
  useEffect(() => {
    let cancelled = false;
    fetch(`/api/rooms/${roomId}/history`)
      .then(r => r.json())
      .then(h => { if (!cancelled) setHistory(h); });
    return () => { cancelled = true; };
  }, [roomId]);

  // Concern 2: WebSocket — isolated in its own effect
  useEffect(() => {
    const socket = new WebSocket(`wss://chat/${roomId}`);
    socket.onmessage = msg => setMessages(ms => [...ms, msg]);
    return () => socket.close(); // cleanup right next to setup
  }, [roomId]);
}

class Counter extends React.Component {
  constructor(props) {
    super(props);              // required
    this.state = { count: 0 };
    this.increment = this.increment.bind(this); // or use arrow class property
  }

  increment() {
    this.setState({ count: this.state.count + 1 });
  }

  render() {
    return (
      <button onClick={this.increment}>
        {this.state.count}
      </button>
    );
  }
}

function Counter() {
  const [count, setCount] = useState(0);
  return (
    <button onClick={() => setCount(c => c + 1)}>
      {count}
    </button>
  );
}

// Built-in hooks (selected)
import {
  useState,       // local state
  useEffect,      // side-effects and cleanup
  useRef,         // mutable ref / DOM access
  useContext,     // read a React context
  useReducer,     // complex state with actions
  useMemo,        // memoize expensive values
  useCallback,    // memoize function references
} from 'react';

// Custom hook — starts with 'use', calls other hooks
function useLocalStorage(key, initialValue) {
  const [value, setValue] = useState(() => {
    try {
      return JSON.parse(localStorage.getItem(key)) ?? initialValue;
    } catch {
      return initialValue;
    }
  });

  const setItem = (newValue) => {
    setValue(newValue);
    localStorage.setItem(key, JSON.stringify(newValue));
  };

  return [value, setItem];
}

// React builds this linked list internally on each render:
// [hook1: { state: 0 }, hook2: { effect: fn }, hook3: { ref: null }, ...]

function Example() {
  const [count, setCount] = useState(0);       // hook record 0
  const [name, setName] = useState('');        // hook record 1
  const ref = useRef(null);                    // hook record 2
  useEffect(() => { document.title = name; }, [name]); // hook record 3
  // ...
}

// Because the list is positional, this is forbidden:
function BadExample({ condition }) {
  if (condition) {
    const [count, setCount] = useState(0); // conditional call — breaks ordering
  }
  // React would try to match hook record 0 against the wrong state slot
}

// A custom hook that packages fetch state
function useFetch(url) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    fetch(url)
      .then(r => { if (!r.ok) throw new Error(r.statusText); return r.json(); })
      .then(d => { if (!cancelled) { setData(d); setLoading(false); } })
      .catch(e => { if (!cancelled) { setError(e.message); setLoading(false); } });
    return () => { cancelled = true; };
  }, [url]);

  return { data, loading, error };
}

// Usage — no boilerplate, clear intent
function UserCard({ userId }) {
  const { data: user, loading, error } = useFetch(`/api/users/${userId}`);
  if (loading) return <p>Loading…</p>;
  if (error) return <p>Error: {error}</p>;
  return <h1>{user.name}</h1>;
}

// The same hook used elsewhere — no duplication
function TeamList({ teamId }) {
  const { data: members, loading } = useFetch(`/api/teams/${teamId}/members`);
  // ...
}

// Valid — starts with 'use', calls hooks inside
function useCounter(initialValue = 0) {
  const [count, setCount] = useState(initialValue);
  const increment = useCallback(() => setCount(c => c + 1), []);
  const reset = useCallback(() => setCount(initialValue), [initialValue]);
  return { count, increment, reset };
}

// Valid — helper function, doesn't call hooks, doesn't need 'use' prefix
function formatCount(count) {
  return count.toLocaleString();
}

// Incorrect — not named with 'use' but calls a hook inside
// ESLint will warn: "React Hook 'useState' cannot be called in a function
// that is not a React function component or a custom React Hook function"
function getCounter() {
  const [count] = useState(0); // ESLint error
  return count;
}

// Perfectly valid: class and function components in the same tree
class App extends React.Component {
  state = { userId: 1 };
  render() {
    return (
      <div>
        <ClassSidebar />                     {/* class component */}
        <UserProfile userId={this.state.userId} />  {/* function component with hooks */}
      </div>
    );
  }
}

// A function component with hooks
function UserProfile({ userId }) {
  const { data: user } = useFetch(`/api/users/${userId}`);
  return user ? <h1>{user.name}</h1> : null;
}

import { useId, useTransition, useDeferredValue } from 'react';

// useId — stable, unique ID safe for server rendering
function PasswordField() {
  const id = useId();
  return (
    <>
      <label htmlFor={id}>Password</label>
      <input id={id} type="password" />
    </>
  );
}

// useTransition — mark low-priority updates
function SearchPage() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [isPending, startTransition] = useTransition();

  function handleChange(e) {
    setQuery(e.target.value); // urgent: update input
    startTransition(() => {
      setResults(search(e.target.value)); // low-priority
    });
  }

  return (
    <>
      <input value={query} onChange={handleChange} />
      {isPending ? <p>Searching…</p> : <ResultList items={results} />}
    </>
  );
}

// useDeferredValue — defer expensive child renders
function App({ query }) {
  const deferredQuery = useDeferredValue(query);
  return <ExpensiveList filter={deferredQuery} />;
}
